CREATE ALGORITHM=MERGE DEFINER=`user_service`@`%` SQL SECURITY DEFINER VIEW `vi_workcount_log` AS select `b`.`Id` AS `Id`,`a`.`Id` AS `WorkOrderId`,`a`.`AppCode` AS `AppCode`,`a`.`OrderType` AS `OrderType`,`fn_GetOrderTypeByCode`(`a`.`OrderType`) AS `OrderTypeName`,`a`.`WorkStatus` AS `WorkStatus`,(case `f`.`TypeStatus` when 1 then concat(convert(`fn_GetServiceOrderStatus`(`a`.`WorkStatus`) using utf8mb4),'请求关闭(客户审核)') when 2 then concat(convert(`fn_GetServiceOrderStatus`(`a`.`WorkStatus`) using utf8mb4),'请求关闭') else convert(`fn_GetServiceOrderStatus`(`a`.`WorkStatus`) using utf8mb4) end) AS `WorkStatusName`,`a`.`ProName` AS `ProName`,`a`.`CityName` AS `CityName`,`a`.`AreaName` AS `AreaName`,`a`.`InstallAddress` AS `InstallAddress`,`a`.`CustSettleId` AS `CustSettleId`,`a`.`CustSettleName` AS `CustSettleName`,`a`.`CustomerId` AS `CustomerId`,`a`.`CustomerName` AS `CustomerName`,`a`.`CustStoreId` AS `CustStoreId`,`a`.`CustStoreName` AS `CustStoreName`,NULL AS `ActualCustStoreName`,`b`.`GeneralGoodsNames` AS `GeneralGoodsNames`,`b`.`ArtificialServicePriceId` AS `ArtificialServicePriceId`,`b`.`ArtificialServicePriceName` AS `ArtificialServicePriceName`,`b`.`ArtificialServicePrice` AS `ArtificialServicePrice`,`b`.`ServiceSubjectName` AS `ServiceSubjectName`,`b`.`SubjectClassCode` AS `SubjectClassCode`,`b`.`ServiceSubjectCode` AS `ServiceSubjectCode`,`b`.`ArtificialServicePriceAmount` AS `ArtificialServicePriceAmount`,`b`.`InternalPrice` AS `InternalPrice`,`b`.`PricingMethodName` AS `PricingMethodName`,`b`.`DeviceAmount` AS `DeviceAmount`,(case `c`.`Privoder` when 0 then '中瑞' when 1 then '客户' end) AS `Privoder`,if((`c`.`ServiceType` = 6),'集中','非集中') AS `IsCentralize`,`d`.`VinNumber` AS `VinNumber`,`e`.`Value` AS `GuaVin`,`d`.`PlateNumber` AS `PlateNumber`,`g`.`CompleteTime` AS `CompleteTime`,`a`.`CreatePersonName` AS `CreatePersonName`,`b`.`ServiceCode` AS `ServiceCode`,`b`.`ServiceName` AS `ServiceName`,ifnull(if((`b`.`ServiceAscription` = ''),NULL,`b`.`ServiceAscription`),convert(ifnull((select (case when (`ud`.`Ascription` = 0) then '外勤' when (`ud`.`Ascription` = 1) then '内勤' when (`ud`.`Ascription` = 2) then '优工' when (`ud`.`Ascription` = 3) then '特工-外访' when (`ud`.`Ascription` = 4) then '特工-催收' end) AS `Ascription` from (`tb_userinfo` `us` join `tb_userdetail` `ud` on((`us`.`Id` = `ud`.`Id`))) where ((`us`.`TeamCode` = 'ZR01ZR001') and (`us`.`Deleted` = 0) and (upper(`us`.`LoginName`) = convert(upper(`b`.`ServiceCode`) using utf8mb4)))),'空') using utf8)) AS `ServiceAscription`,`b`.`RecordCode` AS `RecordCode`,`b`.`RecordName` AS `RecordName`,`b`.`RecordAscription` AS `RecordAscription`,`a`.`Remark` AS `SendRemark`,`c`.`Remark` AS `ServiceRemark`,(case `b`.`TagSign` when 1 then '是' when 0 then '否' end) AS `TagSign`,json_unquote(json_extract(`bj`.`BussinessJson`,' $.ActualRecordPersonInfo.ActualRecordPersonCode')) AS `ActualRecordPersonCode`,json_unquote(json_extract(`bj`.`BussinessJson`,' $.ActualRecordPersonInfo.ActualRecordPersonName')) AS `ActualRecordPersonName`,convert(json_unquote(json_extract(`bj`.`BussinessJson`,'$.ActualRecordPersonInfo.ActualRecordPersonAscription')) using utf8) AS `ActualRecordPersonAscription`,`b`.`InsertTime` AS `InsertTime`,`b`.`ServiceDepartId` AS `ServiceDepartId`,`b`.`ServiceDepartName` AS `ServiceDepartName`,`h`.`FeeValue` AS `DayFeeValue` from ((((((((`tb_workorderinfo` `a` join `rp_workordercount` `b` on(((`b`.`WorkOrderId` = `a`.`Id`) and (`b`.`Deleted` = 0)))) join `tb_workserviceinfo` `c` on(((`c`.`WorkOrderId` = `a`.`Id`) and (`c`.`Deleted` = 0)))) join `tb_workcarinfo` `d` on(((`d`.`WorkOrderId` = `a`.`Id`) and (`d`.`Deleted` = 0)))) left join `tb_custcolumn` `e` on(((`e`.`WorkOrderId` = `a`.`Id`) and (`e`.`TypeCode` = 2) and (`e`.`Deleted` = 0)))) left join `tb_workorderstatus` `f` on(((`f`.`WorkOrderId` = `a`.`Id`) and (`f`.`Deleted` = 0)))) left join `tb_recordinfo` `g` on(((`a`.`Id` = `g`.`WorkOrderId`) and (`g`.`Deleted` = 0)))) left join `tb_workbussinessjsoninfo` `bj` on(((`a`.`Id` = `bj`.`WorkOrderId`) and (`bj`.`Deleted` = 0)))) left join `tb_feeapplicationinfo` `h` on(((`a`.`Id` = `h`.`TargetId`) and (`h`.`AuditStatus` = 2) and (`h`.`Deleted` = 0) and (`h`.`FeeItemId` = 'II9999999457')))) where (`a`.`Deleted` = 0)